import { Migration } from '@nocobase/server';

export default class extends Migration {
  on = 'afterLoad'; // 'beforeLoad' or 'afterLoad'
  appVersion = '<2.1.0';

  async up() {
    const repo = this.db.getRepository('roles');
    const role = await repo.findOne({
      filter: {
        name: 'member',
      },
    });
    if (!role) {
      return;
    }
    await repo.update({
      filter: {
        name: role.name,
      },
      values: {
        strategy: {
          ...role.strategy,
          actions: ['view:own'],
        },
      },
    });
  }
}
